!function(){try{var e="undefined"!=typeof window?window:"undefined"!=typeof global?global:"undefined"!=typeof globalThis?globalThis:"undefined"!=typeof self?self:{},n=(new e.Error).stack;n&&(e._sentryDebugIds=e._sentryDebugIds||{},e._sentryDebugIds[n]="47cd9392-956c-4e1c-8e47-fd79e50f7325",e._sentryDebugIdIdentifier="sentry-dbid-47cd9392-956c-4e1c-8e47-fd79e50f7325")}catch(e){}}();var _global="undefined"!=typeof window?window:"undefined"!=typeof global?global:"undefined"!=typeof globalThis?globalThis:"undefined"!=typeof self?self:{};_global.SENTRY_RELEASE={id:"endfield-returning-user-reward-web@1.0.0"},(self.webpackChunkendfield_returning_user_reward_web=self.webpackChunkendfield_returning_user_reward_web||[]).push([[547],{22547:function(e,n,a){a.r(n),a.d(n,{locale:function(){return d}});var t=a(23068),s=JSON.parse('{"title":"Восстановление протокола","description":"С возвращением на Талос II, Эндминистратор.","guide":{"character":"Перлика","lines":"Удалось отдохнуть, Эндмин? На борту «Дицзян» столько всего произошло! Оперативники из медицинского отдела напоминают: обязательно запишись на медосмотр. Все по тебе соскучились, а я... я тоже жду тебя, Эндмин.","button":"Восстановление протокола"},"home":{"title":"Восстановление протокола","timeCount":"{{DD}} д. {{HH}} ч.","tabs":{"checkIn":"Вход восстановления","task":"Задания восстановления","survey":"Опрос для вернувшихся игроков"},"checkIn":{"title":"Вход восстановления","intro":"Участвуйте в событии «Вход восстановления» в течение 7 дней и получите ороберил х2000 и другие награды!"},"task":{"intro":"Участвуйте в событии «Задания восстановления» и выполняйте различные задания, чтобы получить <b>базовое разрешение на наем х4</b> и другие награды!","taskStatus":{"claimable":"Забрать","ongoing":"Не завершено","claimed":"Получено"},"claimAvailable":"Забрать все","currentPoint":"Текущие очки","taskContent":{"daily_login":"Входите в игру 1 раз в день (выполняется 7 раз)","deploy_factory":"Разместите любое сооружение АПК","battle_enemy":"Победите 10 врагов","clear_stage":"Пройдите протокольный разлом 1 раз","manufacture":"Заберите изделия из производственных отсеков «Дицзян» 1 раз","upgrade_role_level":"Повысьте уровень оперативника 1 раз","collect_ore":"Соберите минеральную руду 1 раз","trade_goods":"Совершите торговую сделку с аванпостом 1 раз","buy_goods":"Купите товары в системе перераспределения резервов 1 раз","trade_credit":"Купите товары в магазине кредитов 1 раз","collect_item":"Соберите 8 розовых грибов","ap_cost":"Потратьте 1000 оч. рассудка","boss_challenge":"Пройдите «Реванш» 1 раз","world_battle":"Очистите аллювий энергии 1 раз (временный аллювий энергии также учитывается)"}},"minimumTimeCount":"<1 ч.","survey":{"surveyStatus":{"not_started":"Не начат","claimed":"Завершен"},"goToButton":"Начать","unlockText":"Откроется через {{timeCount}}","rewardTip":"Завершите опрос, чтобы получить","surveyContent":{"survey_1":"Опрос для вернувшихся игроков (день 1)","survey_2":"Опрос об игре для вернувшихся игроков"},"callbackModal":{"title":"СИСТЕМНОЕ УВЕДОМЛЕНИЕ","content":"Перейдите на новую страницу, чтобы пройти опрос.","button":"Завершено"}}},"rule":{"title":"Сведения о событии «Восстановление протокола»","content":"<b>- Условия участия -</b>\\n<span>· Уровень влияния Эндминистратора ≥ 3.</span>\\n<span>· Завершите основную миссию: операция I главы I «Перезагрузка Долины».</span>\\n<span>· Вход в игру не выполнялся ≥ 21 д. подряд.</span>\\n<span>· Со времени предыдущего события «Восстановление протокола» прошло ≥ 42 д.</span>\\n<span>· Длительность статуса возвращения Эндминистратора совпадает с периодом проведения события «Восстановление протокола».</span>\\n\\n<b>- Правила события -</b>\\n<span>· Эндминистратор, во время события можно получить награду, впервые посетив страницу «Восстановление протокола».</span>\\n<span>· Во время события посещайте страницу «Восстановление протокола» и участвуйте в событиях «Вход восстановления» и «Задания восстановления», чтобы получать награды.</span>\\n<span>· Во время события ежедневно отмечайтесь во «Входе восстановления», чтобы получить награды. Ежедневный вход доступен в течение 7 дней.</span>\\n<span>· Выполняйте различные задания восстановления, чтобы получать очки события и награды. Накопите достаточно очков, чтобы получить бонусные награды.</span>\\n<span>При подсчете данных заданий восстановления возможны небольшие задержки. После выполнения условий задания подождите от 2 до 5 минут, чтобы данные синхронизировались.</span>\\n<span>· Все награды события будут отправлены на почту. Эндминистратор, письма исчезнут через 30 дней, поэтому не забудьте вовремя забрать награды.</span>\\n<span>· Событие закончится через 14 дней после вашего участия в 4:00 (по времени сервера).</span>"},"rewardModal":{"title":"Награды получены","prompt":"Награды отправлены на почту. Не забудьте их забрать, Эндмин.","pointTitle":"Получить очки","closeTip":"Нажмите, чтобы закрыть","closeTip_PC":"Нажмите, чтобы закрыть","closeTip_MB":"Коснитесь, чтобы закрыть"},"gameItem":{"item_gold":{"name":"Т-креды","usage":"Сокращается как ТК. Эту валюту признают и используют во множестве мест.","desc":"Популярная валюта с вшитой продвинутой защитой от подделки. Настоящие деньги — это те, на которые можно что-то купить."},"item_diamond":{"name":"Ороберил","usage":"Искусственный материал. Часто используется для найма оперативников.","desc":"Продукт резки ориджеметрия. Эти камни необычайно популярны из-за красоты и широкого спектра применения."},"item_expcard_stage1_high":{"name":"Подробные записи боя","usage":"Материал, который дает большое количество опыта за повышение оперативников уровней 1-60.","desc":"Устройство с видеозаписями боев. Используется новыми оперативниками для изучения боевых навыков. Также оснащено симуляциями исторических сражений, которые позволяют оценить всю жестокость войн на Талосе II."},"item_weapon_expcard_high":{"name":"Тест-набор для оружия","usage":"Материал, который дает большое количество опыта оружия.","desc":"Одноразовый набор инструментов с технологией АПК. Автоматически проверяет глубинную структуру оружия, ремонтирует внутренние повреждения и значительно улучшает характеристики."},"item_char_break_stage_1_2":{"name":"Протодиск","usage":"Материал для повышения оперативников до Э1 или Э2.","desc":"Особый диск, созданный с помощью технопротокола и стандартных процессов гравировки данных. Его часто используют с другими устройствами, чтобы эффективно снять физическую усталость у оперативников во время тренировок."},"item_ticketgacha_standard_single":{"name":"Базовое разрешение на наем","usage":"Внутренний сертификат компании Endfield. Используйте, чтобы провести 1 попытку в стандартном найме.","desc":"У компании Endfield много связей и ресурсов по всему Талосу II. Как только отдел кадров Endfield начинает наем в определенной отрасли, тут же находятся желающие."},"ap_supply_lt_n":{"name":"Экстренный протектор рассудка","usage":"Используйте, чтобы восстановить 40 оч. рассудка. У предмета ограничен срок действия.","desc":"Сироп рассудка в средней дозировке для употребления в экстренных случаях. Похоже, разработчик наткнулся в странных документах на секретную формулу, позволяющую увеличить содержание сахара в этом препарате."},"item_bp_double_reward":{"name":"Разрешение на поглощение рассудка","usage":"Используйте, чтобы поглотить вдвое больше рассудка и удвоить награды в режимах, поглощающих рассудок. На каждые 10 очков поглощенного рассудка требуется 1 разрешение.","desc":"Разрешение, позволяющее мгновенно поглотить огромное количество рассудка. Чрезмерное истощение рассудка крайне вредно для человека. Прежде чем продолжить, вам нужно будет пройти полное обследование в медицинском отделе."},"item_char_break_stage_3_4":{"name":"Протонабор","usage":"Материал для повышения оперативников до Э3 или Э4.","desc":"Особый диск, созданный с помощью технопротокола и улучшенных процессов гравировки данных. Его часто используют с другими устройствами, чтобы эффективно снять физическую усталость у оперативников во время тренировок."},"item_expcard_stage2_high":{"name":"Улучшенный когнитивный носитель","usage":"Материал, который дает большое количество опыта за повышение оперативников уровней 61-90.","desc":"Модуль памяти, разработанный компанией Endfield. Совместим с разными устройствами для доступа к данным. Используется новыми оперативниками для эффективного освоения боевых навыков. При поддержке секты умиротворения была добавлена технология сжатия данных, за счет чего модуль хранит еще больше информации."},"item_weapon_break_high":{"name":"Тяжелая литейная форма","usage":"Материал для калибровки оружия.","desc":"Тяжелая литейная форма из редких материалов. Благодаря технопротокольной активации усиливает общую прочность материалов в оружии."},"item_char_skill_level_7_12":{"name":"Протоэдр","usage":"Материал для улучшения навыков оперативника.","desc":"Особый кристаллический полиэдр, созданный с помощью технопротокола и продвинутых процессов кристаллизации. Его часто объединяют с другими устройствами, чтобы улучшить усвоение материалов усиления."},"item_case_bp_selfselect_skillsp_1":{"name":"Ящик с выбором улучшенного развития I","usage":"Открыв этот ящик, вы сможете выбрать материалы для ускоренного развития.","desc":"Ящик со всевозможными универсальными материалами высокого качества. Раса и опыт не влияют на боевую эффективность. Порой оперативнику нужно лишь немного вдохновения."}},"errMsg":{"code_2000":"Не удалось отправить награды. Подождите и повторите попытку.","rewardClaimed":"Награда уже получена","code_1002":"Событие загружается. Подождите, прежде чем снова открыть экран события.","code_1003":"Событие завершено","networkError":"Ошибка службы"},"gamepad":{"hint":{"confirm":"Подтвердить","close":"Выкл.","closeCurrent":"Закрыть экран","exit":"Покинуть страницу"}}}'),d={lang:t.ELanguage["ru-ru"],text:s,fonts:{}}}}]);
